// Vervang YOUR_KEY_HERE met je daadwerkelijke Anthropic API key.
const apiKey = 'YOUR_KEY_HERE';

const requestBody = $('System Prompt').first().json.requestBody;

// Retry-logica voor tijdelijke Anthropic-fouten (529 overloaded, 503, 429 rate limit, 5xx).
// Wacht 1s, dan 3s, dan 8s tussen pogingen. Max 3 pogingen.
const MAX_ATTEMPTS = 3;
const BACKOFF_MS = [1000, 3000, 8000];

function getStatusCode(err) {
  if (err.httpCode) return Number(err.httpCode);
  if (err.statusCode) return Number(err.statusCode);
  if (err.response?.status) return Number(err.response.status);
  if (err.cause?.response?.status) return Number(err.cause.response.status);
  const match = String(err.message || '').match(/status code (\d+)/i);
  return match ? Number(match[1]) : null;
}

let data;
let lastError;
for (let attempt = 0; attempt < MAX_ATTEMPTS; attempt++) {
  try {
    data = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: requestBody,
      json: true
    });
    break;
  } catch (err) {
    lastError = err;
    const status = getStatusCode(err);
    if (status !== null && status >= 400 && status < 500 && status !== 429) {
      throw err;
    }
    if (attempt < MAX_ATTEMPTS - 1) {
      console.log(`Anthropic API poging ${attempt + 1} gefaald (status: ${status}). Opnieuw over ${BACKOFF_MS[attempt]}ms...`);
      await new Promise(r => setTimeout(r, BACKOFF_MS[attempt]));
    }
  }
}
if (!data) throw lastError;

// Anthropic geeft bij tool_use vaak GEEN afsluitende tekst. Voeg er zelf een toe
// zodat de bot na lead_capture netjes afsluit ipv te zwijgen.
const hasText = data.content?.some(c => c.type === 'text' && c.text?.trim());
const leadTool = data.content?.find(c => c.type === 'tool_use' && c.name === 'lead_capture');

if (leadTool && !hasText) {
  data.content.push({
    type: 'text',
    text: 'Top, ik heb je gegevens genoteerd. Een van onze experts neemt binnenkort contact met je op. Heb je verder nog vragen waar ik je mee kan helpen?'
  });
}

return [{ json: data }];

// Bouw de lead-melding email: lead-info + volledige chathistorie
const leadData = $('Anthropic API').first().json.content.find(c => c.type === 'tool_use' && c.name === 'lead_capture')?.input || {};
const sessionId = $('Webhook').first().json.body.session_id || '';
const blogSlug = $('Webhook').first().json.body.blog_slug || 'onbekend';
const history = $('Webhook').first().json.body.history || [];
const currentUserMessage = $('Webhook').first().json.body.user_message || '';

function esc(s) {
  return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\n/g, '<br>');
}

// Alle messages = oude history + zojuist binnengekomen user message
const allMessages = [...history, { role: 'user', content: currentUserMessage }];

const historyHtml = allMessages.map(m => {
  const role = m.role === 'user' ? 'Bezoeker' : 'AI assistent';
  const color = m.role === 'user' ? '#1e40af' : '#4b5563';
  const border = m.role === 'user' ? '' : 'padding-left: 12px; border-left: 2px solid #ec4899;';
  return `<div style="color: ${color}; margin-bottom: 12px; ${border}"><strong>${role}:</strong> ${esc(m.content)}</div>`;
}).join('\n');

const leadRows = [
  `<strong>Naam:</strong> ${esc(leadData.naam || '-')}`,
  `<strong>Voorkeur:</strong> ${esc(leadData.contact_voorkeur || '-')}`,
  leadData.email ? `<strong>E-mail:</strong> <a href="mailto:${esc(leadData.email)}">${esc(leadData.email)}</a>` : null,
  leadData.telefoon ? `<strong>Telefoon:</strong> <a href="tel:${esc(leadData.telefoon)}">${esc(leadData.telefoon)}</a>` : null,
  leadData.beste_moment ? `<strong>Beste moment:</strong> ${esc(leadData.beste_moment)}` : null
].filter(Boolean).join('<br>');

const html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
<body style="font-family: -apple-system, Segoe UI, Roboto, sans-serif; color: #1a1a2e; max-width: 600px; margin: 0 auto; padding: 20px;">
  <h1 style="color: #ec4899; font-size: 20px;">Nieuwe lead via AI subsidie assistent</h1>

  <div style="background: #f9fafb; border-left: 4px solid #ec4899; padding: 16px; margin: 16px 0; border-radius: 4px;">
    ${leadRows}
  </div>

  <div style="background: #f9fafb; border-left: 4px solid #ec4899; padding: 16px; margin: 16px 0; border-radius: 4px;">
    <strong>Context (samengevat door bot):</strong><br>
    ${esc(leadData.context || '-')}
  </div>

  <h2 style="color: #1a1a2e; font-size: 16px; margin-top: 24px;">Volledige chathistorie</h2>
  <div style="background: #ffffff; border: 1px solid #e5e7eb; border-radius: 4px; padding: 16px; font-size: 14px; line-height: 1.6;">
    ${historyHtml}
  </div>

  <div style="font-size: 12px; color: #6b7280; margin-top: 24px; padding-top: 16px; border-top: 1px solid #e5e7eb;">
    Sessie-ID: ${esc(sessionId)}<br>
    Blog: ${esc(blogSlug)}
  </div>
</body></html>`;

const subject = `Nieuwe lead via AI subsidie assistent: ${leadData.naam || 'naamloos'}`;

return [{ json: { html, subject } }];
